// ── Tier theming (uses CSS-var-derived colors at render time) ─────────
function useTiers() {
  const { colors } = useTheme();
  return useMemo(() => ({
    common: {
      label: 'Common',
      bg: `${colors.textMuted}18`,
      border: `${colors.textMuted}40`,
      color: colors.textSecondary,
      glow: 'none',
      icon: `${colors.textMuted}30`,
    },
    rare: {
      label: 'Rare',
      bg: `${colors.blue}14`,
      border: `${colors.blue}40`,
      color: colors.blue,
      glow: `0 0 20px ${colors.blue}28`,
      icon: `${colors.blue}30`,
    },
    epic: {
      label: 'Epic',
      bg: `${colors.purple}14`,
      border: `${colors.purple}40`,
      color: colors.purple,
      glow: `0 0 24px ${colors.purple}30`,
      icon: `${colors.purple}30`,
    },
    legendary: {
      label: 'Legendary',
      bg: `${colors.amber}14`,
      border: `${colors.amber}48`,
      color: colors.amber,
      glow: `0 0 30px ${colors.amber}40`,
      icon: `${colors.amber}30`,
    },
  }), [colors]);
}

