// ── Achievement card ─────────────────────────────────────────────────
function AchievementCard({ achievement, isNew, isMobile, onPreview, tiers }) {
  const tier = tiers[achievement.tier] || tiers.common;
  const { colors } = useTheme();
  const earned = achievement.earned;
  const progress = achievement.progress ?? 0;
  const target = achievement.target ?? 1;
  const pts = achievement.points ?? 0;

  return (
    <motion.div
      variants={staggerItem}
      whileHover={earned ? { scale: 1.02, y: -2 } : { scale: 1.01 }}
      className={s.achCardOuter}
    >
      <div
        className={`${isMobile ? s.achCardMobile : s.achCardDesktop} ${earned ? '' : s.achCardLocked}`}
        style={{
          background: earned ? tier.bg : `${colors.surface}99`,
          border: `1px solid ${earned ? tier.border : colors.border}`,
          boxShadow: earned ? tier.glow : 'none',
        }}
      >
        {/* New celebration burst */}
        {isNew && earned && <CelebrationBurst tier={achievement.tier} tiers={tiers} />}

        {/* Header: icon + tier badge */}
        <div className={s.achHeader}>
          <AchievementIcon
            icon={achievement.icon}
            tier={achievement.tier}
            earned={earned}
            size={isMobile ? 36 : 44}
            tiers={tiers}
          />
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
            <span
              className={s.achTierBadge}
              style={{ color: tier.color, background: `${tier.color}15` }}
            >
              {tier.label}
            </span>
            {pts > 0 && (
              <span
                style={{
                  fontFamily: mono,
                  fontSize: 10,
                  fontWeight: 700,
                  color: earned ? colors.amber : colors.textMuted,
                }}
              >
                {pts} pts
              </span>
            )}
          </div>
        </div>

        {/* Name */}
        <div>
          <h3
            className={`${s.achName} ${isMobile ? s.achNameMobile : s.achNameDesktop}`}
            style={{ color: earned ? colors.textPrimary : colors.textMuted }}
          >
            {earned ? achievement.name : '???'}
          </h3>
          <p
            className={s.achDesc}
            style={{ color: earned ? colors.textSecondary : colors.textMuted }}
          >
            {earned ? achievement.description : 'Complete the challenge to reveal'}
          </p>
        </div>

        {/* Progress bar or earned date */}
        {earned ? (
          <div className={s.achEarnedRow}>
            <svg width={12} height={12} viewBox="0 0 24 24" fill="none" stroke={colors.green} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <path d="M20 6L9 17l-5-5" />
            </svg>
            <span className={s.achEarnedLabel} style={{ color: colors.green }}>
              Earned
            </span>
            {onPreview && (
              <button
                onClick={(e) => { e.stopPropagation(); onPreview(achievement); }}
                className={s.achPreviewBtn}
                style={{
                  color: tier.color,
                  background: `${tier.color}15`,
                  border: `1px solid ${tier.color}30`,
                }}
              >
                Preview
              </button>
            )}
            {!onPreview && achievement.earned_date && (
              <span className={s.achEarnedDate} style={{ color: colors.textSecondary }}>
                {achievement.earned_date}
              </span>
            )}
          </div>
        ) : (
          <div className={s.achProgressWrap}>
            <ProgressBar
              current={progress}
              total={target}
              color={tier.color}
            />
          </div>
        )}
      </div>

      {/* NEW badge for recently earned */}
      {isNew && earned && (
        <motion.div
          initial={{ scale: 0, rotate: -12 }}
          animate={{ scale: 1, rotate: 0 }}
          transition={{ type: 'spring', stiffness: 400, damping: 15, delay: 0.3 }}
          className={s.newBadge}
          style={{ background: colors.green }}
        >
          NEW
        </motion.div>
      )}
    </motion.div>
  );
}

// ── Tier progress banner ─────────────────────────────────────────────
function TierBanner({ summary, isMobile, tiers }) {
  const { colors } = useTheme();
  const earned = summary.earned ?? 0;
  const total = summary.total ?? 28;
  const points = summary.points ?? 0;
  const tierLevel = summary.tier_level ?? 'Bronze';
  const tierProgress = summary.tier_progress ?? earned / total;

  const tierColors = {
    Bronze: colors.amber,
    Silver: colors.textSecondary,
    Gold: colors.amber,
    Platinum: colors.cyan,
    Diamond: colors.purple,
  };
  const tierColor = tierColors[tierLevel] || colors.blue;

  return (
    <GlassPanel
      className={isMobile ? s.tierBannerMobile : s.tierBanner}
      style={{
        padding: isMobile ? 16 : 24,
        borderLeft: `3px solid ${tierColor}`,
      }}
    >
      {/* Left: tier badge */}
      <div className={s.tierBadgeRow}>
        <motion.div
          animate={{ rotate: [0, 5, -5, 0] }}
          transition={{ duration: 3, repeat: Infinity, repeatDelay: 2 }}
          className={s.tierBadgeIcon}
          style={{
            background: `${tierColor}15`,
            border: `2px solid ${tierColor}40`,
          }}
        >
          <svg width={28} height={28} viewBox="0 0 24 24" fill={tierColor} opacity={0.9}>
            <path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" />
          </svg>
        </motion.div>
        <div>
          <div className={s.tierCurrentLabel} style={{ color: colors.textSecondary }}>
            Current Tier
          </div>
          <div className={s.tierCurrentName} style={{ color: tierColor }}>
            {tierLevel}
          </div>
        </div>
      </div>

      {/* Center: progress + points */}
      <div className={s.tierProgressSection}>
        <div className={s.tierProgressRow}>
          <span className={s.tierProgressCount} style={{ color: colors.textPrimary }}>
            {earned}
          </span>
          <span className={s.tierProgressTotal} style={{ color: colors.textSecondary }}>
            / {total} earned
          </span>
          <span style={{
            fontFamily: mono,
            fontSize: 14,
            fontWeight: 700,
            color: colors.amber,
            marginLeft: 'auto',
          }}>
            {points.toLocaleString()} pts
          </span>
        </div>
        <div className={s.tierProgressTrack} style={{ background: colors.border }}>
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${tierProgress * 100}%` }}
            transition={{ duration: 1.2, ease: [0.4, 0, 0.2, 1] }}
            className={s.tierProgressFill}
            style={{ background: `linear-gradient(90deg, ${tierColor}, ${tierColor}CC)` }}
          />
        </div>
      </div>

      {/* Right: tier breakdown */}
      <div className={s.tierBreakdown}>
        {Object.entries(summary.by_tier ?? {}).map(([tier, data]) => {
          const t = tiers[tier] || tiers.common;
          return (
            <div key={tier} className={s.tierBreakdownItem}>
              <div className={s.tierBreakdownCount} style={{ color: t.color }}>
                {data.earned ?? 0}
              </div>
              <div className={s.tierBreakdownLabel} style={{ color: colors.textSecondary }}>
                {t.label}
              </div>
            </div>
          );
        })}
      </div>
    </GlassPanel>
  );
}

